    fun `should follow user successfully`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"
        val follower = UserEntity(id = followerId, nickname = "팔로워")
        val following = UserEntity(id = followingId, nickname = "팔로잉대상")
        val savedFollow = UserFollowEntity(id = "follow-id", followerId = followerId, followingId = followingId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followingId)).thenReturn(Optional.of(following))
        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)
        `when`(userFollowRepository.save(any(UserFollowEntity::class.java))).thenReturn(savedFollow)

        // when
        val result = userService.follow(followerId, followingId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followingId).isEqualTo(followingId)
        verify(userFollowRepository).save(any(UserFollowEntity::class.java))
    }

