    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = "lonely-user-id"

        `when`(userFollowRepository.findByFollowingId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
