    }

    // =========================================================
    // getFollowings()
    // =========================================================

    @Test
    fun `should return followings list by userId`() {
        // given
        val userId = "user-id"
        val followings = listOf(
            UserFollowEntity(id = "f1", followerId = userId, followingId = "following-1"),
            UserFollowEntity(id = "f2", followerId = userId, followingId = "following-2"),
