        `when`(userFollowRepository.findByFollowerId(userId)).thenReturn(followings)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followingId }).containsExactly("following-1", "following-2")
        verify(userFollowRepository).findByFollowerId(userId)
    }

    @Test
    fun `should return empty list when user follows nobody`() {
        // given
        val userId = "no-following-user-id"

        `when`(userFollowRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
        verify(userFollowRepository).findByFollowerId(userId)
    }

    // =========================================================
    // isFollowing()
    // =========================================================

    @Test
    fun `should return true when following relationship exists`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"

        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isTrue()
    }

    @Test
    fun `should return false when following relationship does not exist`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"

        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isFalse()
    }

    @Test
    fun `should return false when checking self following`() {
        // given
        val userId = "user-id"

        // when
        val result = userService.isFollowing(userId, userId)

        // then
        assertThat(result).isFalse()
        verifyNoInteractions(userFollowRepository)
    }
}
