import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.*
import org.mockito.junit.jupiter.MockitoExtension
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var userFollowRepository: UserFollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // =========================================================
    // follow()
    // =========================================================

    @Test
    fun `should follow user successfully`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"
        val follower = UserEntity(id = followerId, nickname = "팔로워")
        val following = UserEntity(id = followingId, nickname = "팔로잉대상")
        val savedFollow = UserFollowEntity(id = "follow-id", followerId = followerId, followingId = followingId)

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followingId)).thenReturn(Optional.of(following))
        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)
        `when`(userFollowRepository.save(any(UserFollowEntity::class.java))).thenReturn(savedFollow)

        // when
        val result = userService.follow(followerId, followingId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followingId).isEqualTo(followingId)
        verify(userFollowRepository).save(any(UserFollowEntity::class.java))
    }

    @Test
    fun `should throw SelfFollowException when follower and following are same`() {
        // given
        val userId = "same-user-id"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }

        verifyNoInteractions(userRepository)
        verifyNoInteractions(userFollowRepository)
    }

    @Test
    fun `should throw NotFoundException when follower does not exist`() {
        // given
        val followerId = "non-existent-follower"
        val followingId = "following-id"

        `when`(userRepository.findById(followerId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            userService.follow(followerId, followingId)
        }

        verify(userRepository).findById(followerId)
        verifyNoInteractions(userFollowRepository)
    }

    @Test
    fun `should throw NotFoundException when following user does not exist`() {
        // given
        val followerId = "follower-id"
        val followingId = "non-existent-following"
        val follower = UserEntity(id = followerId, nickname = "팔로워")

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followingId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFoundException> {
            userService.follow(followerId, followingId)
        }

        verify(userRepository).findById(followingId)
        verifyNoInteractions(userFollowRepository)
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"
        val follower = UserEntity(id = followerId, nickname = "팔로워")
        val following = UserEntity(id = followingId, nickname = "팔로잉대상")

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(follower))
        `when`(userRepository.findById(followingId)).thenReturn(Optional.of(following))
        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followingId)
        }

        verify(userFollowRepository, never()).save(any())
    }

    // =========================================================
    // unfollow()
    // =========================================================

    @Test
    fun `should unfollow user successfully`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"
        val existingFollow = UserFollowEntity(id = "follow-id", followerId = followerId, followingId = followingId)

        `when`(userFollowRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(existingFollow)

        // when
        userService.unfollow(followerId, followingId)

        // then
        verify(userFollowRepository).delete(existingFollow)
    }

    @Test
    fun `should throw NotFoundException when unfollow target relationship does not exist`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"

        `when`(userFollowRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(null)

        // when & then
        assertThrows<NotFoundException> {
            userService.unfollow(followerId, followingId)
        }

        verify(userFollowRepository, never()).delete(any(UserFollowEntity::class.java))
    }

    @Test
    fun `should throw SelfFollowException when unfollow self`() {
        // given
        val userId = "same-user-id"

        // when & then
        assertThrows<SelfFollowException> {
            userService.unfollow(userId, userId)
        }

        verifyNoInteractions(userFollowRepository)
    }

    // =========================================================
    // getFollowers()
    // =========================================================

    @Test
    fun `should return followers list by userId`() {
        // given
        val userId = "user-id"
        val followers = listOf(
            UserFollowEntity(id = "f1", followerId = "follower-1", followingId = userId),
            UserFollowEntity(id = "f2", followerId = "follower-2", followingId = userId),
        )

        `when`(userFollowRepository.findByFollowingId(userId)).thenReturn(followers)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followerId }).containsExactly("follower-1", "follower-2")
        verify(userFollowRepository).findByFollowingId(userId)
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = "lonely-user-id"

        `when`(userFollowRepository.findByFollowingId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
        verify(userFollowRepository).findByFollowingId(userId)
    }

    // =========================================================
    // getFollowings()
    // =========================================================

    @Test
    fun `should return followings list by userId`() {
        // given
        val userId = "user-id"
        val followings = listOf(
            UserFollowEntity(id = "f1", followerId = userId, followingId = "following-1"),
            UserFollowEntity(id = "f2", followerId = userId, followingId = "following-2"),
        )

        `when`(userFollowRepository.findByFollowerId(userId)).thenReturn(followings)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followingId }).containsExactly("following-1", "following-2")
        verify(userFollowRepository).findByFollowerId(userId)
    }

    @Test
    fun `should return empty list when user follows nobody`() {
        // given
        val userId = "no-following-user-id"

        `when`(userFollowRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
        verify(userFollowRepository).findByFollowerId(userId)
    }

    // =========================================================
    // isFollowing()
    // =========================================================

    @Test
    fun `should return true when following relationship exists`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"

        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isTrue()
    }

    @Test
    fun `should return false when following relationship does not exist`() {
        // given
        val followerId = "follower-id"
        val followingId = "following-id"

        `when`(userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isFalse()
    }

    @Test
    fun `should return false when checking self following`() {
        // given
        val userId = "user-id"

        // when
        val result = userService.isFollowing(userId, userId)

        // then
        assertThat(result).isFalse()
        verifyNoInteractions(userFollowRepository)
    }
}
