### 3. Green 단계 - 테스트를 통과하는 최소 구현 (TDD Step 2)

**파일 위치:** `user-service/src/main/kotlin/com/maum/backend/service/UserService.kt`

```kotlin
package com.maum.backend.service

import com.maum.backend.entity.user.UserFollowEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.user.UserFollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
@Transactional(readOnly = true)
class UserService(
    private val userRepository: UserRepository,
    private val userFollowRepository: UserFollowRepository,
) {

    /**
     * 사용자를 팔로우한다.
     * @throws SelfFollowException 자기 자신을 팔로우하는 경우
     * @throws NotFoundException 팔로워 또는 팔로잉 대상이 존재하지 않는 경우
     * @throws AlreadyFollowingException 이미 팔로우 중인 경우
     */
    @Transactional
    fun follow(followerId: String, followingId: String): UserFollowEntity {
        if (followerId == followingId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }

        userRepository.findById(followerId)
            .orElseThrow { NotFoundException("팔로워 사용자를 찾을 수 없습니다: $followerId") }

        userRepository.findById(followingId)
            .orElseThrow { NotFoundException("팔로잉 대상 사용자를 찾을 수 없습니다: $followingId") }

        if (userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw AlreadyFollowingException("이미 팔로우 중입니다.")
        }

        val follow = UserFollowEntity(
            followerId = followerId,
            followingId = followingId,
        )
        return userFollowRepository.save(follow)
    }

    /**
     * 사용자 팔로우를 취소한다.
     * @throws SelfFollowException 자기 자신을 언팔로우하려는 경우
     * @throws NotFoundException 팔로우 관계가 존재하지 않는 경우
     */
    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        if (followerId == followingId) {
            throw SelfFollowException("자기 자신을 언팔로우할 수 없습니다.")
        }

        val follow = userFollowRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw NotFoundException("팔로우 관계를 찾을 수 없습니다.")

        userFollowRepository.delete(follow)
    }

    /**
     * 특정 사용자의 팔로워 목록을 조회한다.
     */
    fun getFollowers(userId: String): List<UserFollowEntity> {
        return userFollowRepository.findByFollowingId(userId)
    }

    /**
     * 특정 사용자가 팔로우하는 목록을 조회한다.
     */
    fun getFollowings(userId: String): List<UserFollowEntity> {
        return userFollowRepository.findByFollowerId(userId)
    }

    /**
     * 팔로우 여부를 확인한다.
     * 자기 자신을 확인하면 항상 false를 반환한다.
     */
    fun isFollowing(followerId: String, followingId: String): Boolean {
        if (followerId == followingId) return false
        return userFollowRepository.existsByFollowerIdAndFollowingId(followerId, followingId)
    }
}
